import json
import logging
import os
from typing import Any, Dict, Optional

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent


app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)


def get_env(name: str, default: Optional[str] = None) -> str:
    value = os.getenv(name, default)
    if value is None:
        raise ValueError(f"Missing required environment variable: {name}")
    return value


def get_credential() -> DefaultAzureCredential:
    return DefaultAzureCredential(exclude_interactive_browser_credential=False)


def get_blob_service_client() -> BlobServiceClient:
    account_url = get_env("STORAGE_ACCOUNT_URL")
    return BlobServiceClient(account_url=account_url, credential=get_credential())


def get_cosmos_client() -> CosmosClient:
    endpoint = get_env("COSMOS_ENDPOINT")
    return CosmosClient(url=endpoint, credential=get_credential())


def get_eventgrid_client() -> EventGridPublisherClient:
    endpoint = get_env("EVENTGRID_TOPIC_ENDPOINT")
    return EventGridPublisherClient(endpoint=endpoint, credential=get_credential())


def ensure_cosmos_container(client: CosmosClient):
    database_name = get_env("COSMOS_DATABASE_NAME", "mvp-db")
    container_name = get_env("COSMOS_CONTAINER_NAME", "processed-files")
    database = client.create_database_if_not_exists(id=database_name)
    container = database.create_container_if_not_exists(
        id=container_name,
        partition_key=PartitionKey(path="/partitionKey"),
        offer_throughput=400,
    )
    return container


def process_blob_content(blob_name: str, content: bytes) -> Dict[str, Any]:
    text = content.decode("utf-8", errors="replace")
    lines = [line for line in text.splitlines() if line.strip()]
    words = text.split()
    return {
        "blobName": blob_name,
        "sizeBytes": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "preview": text[:500],
    }


def write_result_to_cosmos(result: Dict[str, Any]) -> Dict[str, Any]:
    cosmos_client = get_cosmos_client()
    container = ensure_cosmos_container(cosmos_client)
    item = {
        "id": result["blobName"].replace("/", "_"),
        "partitionKey": "processed",
        "status": "processed",
        "result": result,
    }
    return container.upsert_item(item)


def send_event(result_item: Dict[str, Any]) -> None:
    client = get_eventgrid_client()
    subject_prefix = get_env("EVENTGRID_SUBJECT_PREFIX", "files/processed")
    event = EventGridEvent(
        subject=f"{subject_prefix}/{result_item['id']}",
        event_type="Contoso.FileProcessed",
        data_version="1.0",
        data={
            "id": result_item["id"],
            "status": result_item["status"],
            "blobName": result_item["result"]["blobName"],
            "sizeBytes": result_item["result"]["sizeBytes"],
            "lineCount": result_item["result"]["lineCount"],
            "wordCount": result_item["result"]["wordCount"],
        },
    )
    client.send([event])


@app.function_name(name="ProcessBlobToCosmosAndEventGrid")
@app.route(route="process-file", methods=["POST"])
def process_file(req: func.HttpRequest) -> func.HttpResponse:
    try:
        body = req.get_json()
        container_name = body["container"]
        blob_name = body["blobName"]

        blob_service = get_blob_service_client()
        blob_client = blob_service.get_blob_client(container=container_name, blob=blob_name)
        content = blob_client.download_blob().readall()

        result = process_blob_content(blob_name, content)
        cosmos_item = write_result_to_cosmos(result)
        send_event(cosmos_item)

        response = {
            "message": "File processed successfully",
            "blobName": blob_name,
            "cosmosId": cosmos_item["id"],
        }
        return func.HttpResponse(json.dumps(response), status_code=200, mimetype="application/json")
    except Exception as exc:
        logging.exception("Processing failed")
        return func.HttpResponse(
            json.dumps({"error": str(exc)}),
            status_code=500,
            mimetype="application/json",
        )